from agent import *from models.products import *import simplejsondef run(context, session):    session.queue(Request('https://tech.hindustantimes.com/mobile/reviews'), process_revlist, dict())def process_revlist(data, context, session):    revs = data.xpath("//div[@class='ltSide' or @class='rtSide']/a")    for rev in revs:        name = rev.xpath("following-sibling::div[@class='sixRatioNine']/div[@class='heading']/text()").string()        if not name:            name = rev.xpath("following-sibling::div[@class='title']/text()").string()        url = rev.xpath("@href").string()        session.queue(Request(url), process_review, dict(context, name=name, url=url))    next_url = data.xpath("//link[@rel='next']/@href").string()    if next_url:        session.queue(Request(next_url), process_revlist, dict())def process_review(data, context, session):    info = data.xpath("//div[@id='entryArticle']/script/text()").string()    product = Product()    product.name = context["name"]    product.url = context["url"]    product.category = "Mobile reviews"    product.ssid = product.url.split('/')[-1].split('.')[0].split('-')[-1]    review = Review()    review.type = "pro"    review.title = context["name"]    review.url = product.url    review.ssid = product.ssid    review.date = data.xpath("//span[@class='date']/text()").string().split(',')[0].strip()    if info:        info = simplejson.loads(info)        product.name = info["name"]        product.manufacturer = info.get("itemReviewed", {}).get("brand", {}).get("name")        grade_overall = info.get("reviewRating", {}).get("ratingValue")        if grade_overall:            review.grades.append(Grade(type="overall", value=float(grade_overall), best=5.0, worst=1.0))    author = data.xpath("//div[@class='whowhen']/a").first()    if author:        name = author.xpath("span/text()").string()        url = author.xpath("@href").string()        ssid = url.split('/')[-1]        review.authors.append(Person(name=name, ssid=ssid, profile_url=url))    pros = data.xpath("//ul[@class='prop']/li/text()").strings()    for pro in pros:        review.add_property(type="pros", value=pro)    cons = data.xpath("//ul[@class='cons']/li/text()").strings()    for con in cons:        review.add_property(type="cons", value=con)    summary = data.xpath("//div[@class='articleDescription']/text()").string()    if summary:        review.add_property(type="summary", value=summary)    conclusion = data.xpath("//div[@id='entryArticle']/h2[regexp:test(., 'verdict', 'i')]/following-sibling::p//text()").string(multiple=True)    if not conclusion:        conclusion = data.xpath("//div[@id='entryArticle']/p[strong][regexp:test(., 'conclusion', 'i')]/following-sibling::p//text()").string(multiple=True)    if conclusion:        review.add_property(type="conclusion", value=conclusion)    excerpt = data.xpath("//div[@id='entryArticle']/p[not(strong)]//text()").string(multiple=True)    if excerpt:        if conclusion:            excerpt = excerpt.replace(conclusion.strip(), '').strip()        review.add_property(type="excerpt", value=excerpt)        product.reviews.append(review)        session.emit(product)